package main

import (
	"container/heap"
)

type Edge struct {
	v     int64
	start int64
	end   int64
}

type Item struct {
	time int64
	node int64
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].time < pq[j].time
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(n int64, edges [][]int64) int64 {
	graph := make(map[int64][]Edge)
	for _, e := range edges {
		u, v, start, end := e[0], e[1], e[2], e[3]
		graph[u] = append(graph[u], Edge{v, start, end})
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{0, 0})

	visited := make(map[int64]int64)

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		currentTime, node := item.time, item.node

		if node == n-1 {
			return currentTime
		}

		if t, exists := visited[node]; exists && t <= currentTime {
			continue
		}
		visited[node] = currentTime

		// Option to stay at current node (wait for 1 time unit)
		heap.Push(&pq, &Item{currentTime + 1, node})

		// Explore all outgoing edges
		for _, edge := range graph[node] {
			if edge.start <= currentTime && currentTime <= edge.end {
				arrivalTime := currentTime + 1
				if t, exists := visited[edge.v]; !exists || arrivalTime < t {
					heap.Push(&pq, &Item{arrivalTime, edge.v})
				}
			}
		}
	}

	return -1
}
