import heapq
from collections import defaultdict

def solve(n: int, edges: list[list[int]]) -> int:
    graph = defaultdict(list)
    for u, v, start, end in edges:
        graph[u].append((v, start, end))

    heap = []
    heapq.heappush(heap, (0, 0))  # (current_time, node)
    visited = {}

    while heap:
        current_time, node = heapq.heappop(heap)
        if node == n - 1:
            return current_time
        if node in visited and visited[node] <= current_time:
            continue
        visited[node] = current_time

        # Option to stay at current node (wait for 1 time unit)
        heapq.heappush(heap, (current_time + 1, node))

        # Explore all outgoing edges
        for v, start, end in graph.get(node, []):
            if start <= current_time <= end:
                arrival_time = current_time + 1
                if v not in visited or arrival_time < visited.get(v, float('inf')):
                    heapq.heappush(heap, (arrival_time, v))

    return -1
